import React, { useEffect, useState } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { 
  Typography, 
  Grid, 
  Paper, 
  Box, 
  Card, 
  CardContent,
  CardHeader,
  Button,
  CircularProgress,
  List,
  ListItem,
  ListItemText,
  ListItemIcon,
  ListItemButton,
  Divider,
  Avatar
} from '@mui/material';
import {
  School as SchoolIcon,
  Group as GroupIcon,
  MenuBook as MenuBookIcon,
  Notifications as NotificationsIcon,
  Person as PersonIcon,
  TrendingUp as TrendingUpIcon,
  ArrowForward as ArrowForwardIcon,
  PeopleAlt as PeopleAltIcon,
  SupervisorAccount as SupervisorAccountIcon,
  Face as FaceIcon
} from '@mui/icons-material';
import { Link as RouterLink } from 'react-router-dom';
import { Chart as ChartJS, ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title } from 'chart.js';
import { Pie, Bar } from 'react-chartjs-2';

// Import action creators
import { getUsers } from '../../features/users/userSlice';
import { getSchools } from '../../features/schools/schoolSlice';
import { getSubjects } from '../../features/subjects/subjectSlice';
import { getDirections } from '../../features/directions/directionSlice';
import { getMyNotifications } from '../../features/notifications/notificationSlice';

// Register ChartJS components
ChartJS.register(ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title);

const AdminDashboard = () => {
  const dispatch = useDispatch();
  const { user } = useSelector((state) => state.auth);

  // Get data from Redux store
  const { users } = useSelector((state) => state.users);
  const { schools } = useSelector((state) => state.schools);
  const { subjects } = useSelector((state) => state.subjects);
  const { directions } = useSelector((state) => state.directions);
  const { notifications } = useSelector((state) => state.notifications);

  // Loading states
  const { isLoading: usersLoading } = useSelector((state) => state.users);
  const { isLoading: schoolsLoading } = useSelector((state) => state.schools);
  const { isLoading: subjectsLoading } = useSelector((state) => state.subjects);
  const { isLoading: directionsLoading } = useSelector((state) => state.directions);
  const { isLoading: notificationsLoading } = useSelector((state) => state.notifications);

  const isLoading = usersLoading || schoolsLoading || subjectsLoading || directionsLoading || notificationsLoading;

  // Calculate stats from real data
  const [stats, setStats] = useState({
    totalStudents: 0,
    totalTeachers: 0,
    totalSchools: 0,
    totalSubjects: 0,
    totalDirections: 0,
    totalNotifications: 0,
    recentUsers: []
  });

  // Update stats when data changes
  useEffect(() => {
    const studentCount = Array.isArray(users) ? users.filter(user => user && user.role === 'student').length : 0;
    const teacherCount = Array.isArray(users) ? users.filter(user => user && user.role === 'teacher').length : 0;
    const schoolCount = Array.isArray(schools) ? schools.length : 0;
    const subjectCount = Array.isArray(subjects) ? subjects.length : 0;
    const directionCount = Array.isArray(directions) ? directions.length : 0;
    const notificationCount = Array.isArray(notifications) ? notifications.length : 0;

    // Get recent users (at most 5)
    let recentUsersList = [];
    if (Array.isArray(users) && users.length > 0) {
      // Sort users by creation date (newest first)
      const sortedUsers = [...users]
        .filter(user => user && user.createdAt)
        .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));

      // Take the first 5
      recentUsersList = sortedUsers.slice(0, 5).map(user => ({
        id: user._id,
        name: user.name,
        role: user.role,
        avatar: user.avatar,
        date: user.createdAt
      }));
    }

    setStats({
      totalStudents: studentCount,
      totalTeachers: teacherCount,
      totalSchools: schoolCount,
      totalSubjects: subjectCount,
      totalDirections: directionCount,
      totalNotifications: notificationCount,
      recentUsers: recentUsersList
    });
  }, [users, schools, subjects, directions, notifications]);

  // Fetch data on component mount with force refresh  
  useEffect(() => {
    // Clear any stale data in localStorage (this helps with browser cache issues)
    const storageKeys = [
      'persist:users',
      'persist:schools',
      'persist:subjects',
      'persist:directions',
      'persist:notifications'
    ];

    // Clear specific cached data to force refresh
    storageKeys.forEach(key => {
      try {
        if (localStorage.getItem(key)) {
          localStorage.removeItem(key);
        }
      } catch (error) {
        console.error(`Error clearing ${key} from localStorage:`, error);
      }
    });

    // Now fetch fresh data
    dispatch(getUsers());
    dispatch(getSchools());
    dispatch(getSubjects());
    dispatch(getDirections());
    dispatch(getMyNotifications());

    // Clean up function
    return () => {
      // Any cleanup if needed
    };
  }, [dispatch]);

  // Force refresh every time the dashboard is shown
  useEffect(() => {
    // This will re-fetch data when the dashboard is revisited
    const interval = setInterval(() => {
      if (document.visibilityState === 'visible') {
        dispatch(getUsers());
        dispatch(getSchools());
        dispatch(getSubjects());
        dispatch(getDirections());
        dispatch(getMyNotifications());
      }
    }, 60000); // Check every minute

    return () => clearInterval(interval);
  }, [dispatch]);

  // Pie chart data for user roles
  const userRolesData = {
    labels: ['Students', 'Teachers', 'Admins'],
    datasets: [
      {
        data: [stats.totalStudents, stats.totalTeachers, 1], // Assuming 1 admin (the current user)
        backgroundColor: [
          'rgba(54, 162, 235, 0.6)',
          'rgba(255, 99, 132, 0.6)',
          'rgba(255, 206, 86, 0.6)',
        ],
        borderColor: [
          'rgba(54, 162, 235, 1)',
          'rgba(255, 99, 132, 1)',
          'rgba(255, 206, 86, 1)',
        ],
        borderWidth: 1,
      },
    ],
  };

  // Bar chart data for entity counts
  const entitiesData = {
    labels: ['Schools', 'Directions', 'Subjects', 'Notifications'],
    datasets: [
      {
        label: 'Count',
        data: [stats.totalSchools, stats.totalDirections, stats.totalSubjects, stats.totalNotifications],
        backgroundColor: 'rgba(75, 192, 192, 0.6)',
        borderColor: 'rgba(75, 192, 192, 1)',
        borderWidth: 1,
      },
    ],
  };

  // Bar chart options
  const barOptions = {
    responsive: true,
    plugins: {
      legend: {
        position: 'top',
      },
      title: {
        display: true,
        text: 'Entity Distribution',
      },
    },
  };

  useEffect(() => {
    // In a real app, you would fetch dashboard data here
    dispatch(getUsers()); // Simulating data fetch
  }, [dispatch]);

  if (isLoading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="60vh">
        <CircularProgress />
      </Box>
    );
  }

  return (
    <Box sx={{ flexGrow: 1 }}>
      <Typography variant="h4" sx={{ mb: 4, fontWeight: 'bold' }}>
        Admin Dashboard
      </Typography>

      {/* Stats Cards */}
      <Grid container spacing={3} sx={{ mb: 4 }}>
        <Grid item xs={12} sm={6} md={3}>
          <Card elevation={3} sx={{ borderRadius: 2, height: '100%' }}>
            <CardContent sx={{ textAlign: 'center' }}>
              <Avatar sx={{ bgcolor: 'primary.main', width: 56, height: 56, mx: 'auto', mb: 2 }}>
                <FaceIcon fontSize="large" />
              </Avatar>
              <Typography variant="h5" component="div" fontWeight="bold">
                {stats.totalStudents}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Students
              </Typography>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} sm={6} md={3}>
          <Card elevation={3} sx={{ borderRadius: 2, height: '100%' }}>
            <CardContent sx={{ textAlign: 'center' }}>
              <Avatar sx={{ bgcolor: 'secondary.main', width: 56, height: 56, mx: 'auto', mb: 2 }}>
                <SupervisorAccountIcon fontSize="large" />
              </Avatar>
              <Typography variant="h5" component="div" fontWeight="bold">
                {stats.totalTeachers}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Teachers
              </Typography>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} sm={6} md={3}>
          <Card elevation={3} sx={{ borderRadius: 2, height: '100%' }}>
            <CardContent sx={{ textAlign: 'center' }}>
              <Avatar sx={{ bgcolor: 'success.main', width: 56, height: 56, mx: 'auto', mb: 2 }}>
                <SchoolIcon fontSize="large" />
              </Avatar>
              <Typography variant="h5" component="div" fontWeight="bold">
                {stats.totalSchools}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Schools
              </Typography>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} sm={6} md={3}>
          <Card elevation={3} sx={{ borderRadius: 2, height: '100%' }}>
            <CardContent sx={{ textAlign: 'center' }}>
              <Avatar sx={{ bgcolor: 'warning.main', width: 56, height: 56, mx: 'auto', mb: 2 }}>
                <MenuBookIcon fontSize="large" />
              </Avatar>
              <Typography variant="h5" component="div" fontWeight="bold">
                {stats.totalSubjects}
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Subjects
              </Typography>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      {/* Charts and Recent Users */}
      <Grid container spacing={3}>
        <Grid item xs={12} md={6}>
          <Paper elevation={3} sx={{ p: 3, borderRadius: 2, height: '100%' }}>
            <Typography variant="h6" sx={{ mb: 2 }}>
              User Distribution
            </Typography>
            <Box sx={{ height: 300, display: 'flex', justifyContent: 'center' }}>
              <Pie data={userRolesData} />
            </Box>
          </Paper>
        </Grid>

        <Grid item xs={12} md={6}>
          <Paper elevation={3} sx={{ p: 3, borderRadius: 2, height: '100%' }}>
            <Typography variant="h6" sx={{ mb: 2 }}>
              Entity Statistics
            </Typography>
            <Box sx={{ height: 300 }}>
              <Bar options={barOptions} data={entitiesData} />
            </Box>
          </Paper>
        </Grid>

        <Grid item xs={12} md={6}>
          <Paper elevation={3} sx={{ p: 3, borderRadius: 2 }}>
            <Typography variant="h6" sx={{ mb: 2 }}>
              Recent Users
            </Typography>
            <List>
              {stats.recentUsers.map((user, index) => (
                <React.Fragment key={user.id}>
                  <ListItem disablePadding>
                    <ListItemButton>
                      <ListItemIcon>
                        <Avatar>
                          {user.role === 'student' ? <FaceIcon /> : <SupervisorAccountIcon />}
                        </Avatar>
                      </ListItemIcon>
                      <ListItemText 
                        primary={user.name} 
                        secondary={`${user.role.charAt(0).toUpperCase() + user.role.slice(1)} • Joined on ${new Date(user.date).toLocaleDateString()}`} 
                      />
                    </ListItemButton>
                  </ListItem>
                  {index < stats.recentUsers.length - 1 && <Divider variant="inset" component="li" />}
                </React.Fragment>
              ))}
            </List>
            <Box sx={{ mt: 2, display: 'flex', justifyContent: 'flex-end' }}>
              <Button 
                component={RouterLink} 
                to="/app/admin/users" 
                endIcon={<ArrowForwardIcon />}
                size="small"
              >
                View All Users
              </Button>
            </Box>
          </Paper>
        </Grid>

        <Grid item xs={12} md={6}>
          <Paper elevation={3} sx={{ p: 3, borderRadius: 2 }}>
            <Typography variant="h6" sx={{ mb: 2 }}>
              Quick Actions
            </Typography>
            <Grid container spacing={2}>
              <Grid item xs={12} sm={6}>
                <Button
                  variant="outlined"
                  fullWidth
                  size="large"
                  component={RouterLink}
                  to="/app/admin/users/create"
                  startIcon={<PersonIcon />}
                  sx={{ py: 1.5, justifyContent: 'flex-start' }}
                >
                  Add New User
                </Button>
              </Grid>
              <Grid item xs={12} sm={6}>
                <Button
                  variant="outlined"
                  fullWidth
                  size="large"
                  component={RouterLink}
                  to="/app/admin/schools"
                  startIcon={<SchoolIcon />}
                  sx={{ py: 1.5, justifyContent: 'flex-start' }}
                >
                  Manage Schools
                </Button>
              </Grid>
              <Grid item xs={12} sm={6}>
                <Button
                  variant="outlined"
                  fullWidth
                  size="large"
                  component={RouterLink}
                  to="/app/admin/subjects"
                  startIcon={<MenuBookIcon />}
                  sx={{ py: 1.5, justifyContent: 'flex-start' }}
                >
                  Manage Subjects
                </Button>
              </Grid>
              <Grid item xs={12} sm={6}>
                <Button
                  variant="outlined"
                  fullWidth
                  size="large"
                  component={RouterLink}
                  to="/app/admin/directions"
                  startIcon={<TrendingUpIcon />}
                  sx={{ py: 1.5, justifyContent: 'flex-start' }}
                >
                  Manage Directions
                </Button>
              </Grid>
            </Grid>
          </Paper>
        </Grid>
      </Grid>
    </Box>
  );
};

export default AdminDashboard;
